sql:
SELECT COUNT(*) AS coverage_count
FROM media_coverage
WHERE athlete_id = 0;

SELECT MAX(earnings_million) AS max_earnings
FROM earnings
WHERE year = 2020;

external_knowledge:
Recent year; refers to the year with the highest value in the 'year' column of the 'ranking_history' table; 
Participated in at least one tournament; refers to having a value greater than 0 in the 'tournaments_played' column; 
Excluding sports with zero average earnings; refers to having an average value greater than 0 in the 'earnings_million' column.

sql:
SELECT MIN(rank) AS highest_ranking_position
FROM ranking_history
WHERE year = 2020;
